impl Lasso {
    /// Fit a Lasso regression model using coordinate descent
    ///
    /// This implementation uses coordinate descent optimization with L1 regularization
    /// to encourage sparse solutions.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `lambda` - L1 regularization parameter (higher values = more regularization)
    /// * `config` - Optional coordinate descent configuration
    pub fn fit(
        x: ArrayView2<f64>,
        y: ArrayView1<f64>,
        lambda: f64,
        config: Option<CoordinateDescentConfig>,
    ) -> Result<RegularizedFit, ModelError> {
        let mut config = config.unwrap_or_default();
        config.lambda = lambda;
        config.alpha = 1.0; // Pure Lasso (L1 only)

        let result = coordinate_descent(x, y, Some(config))
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        let fitted_values: Vec<f64> = result.linear_predictor.to_vec();
        let residuals: Vec<f64> = y
            .iter()
            .zip(fitted_values.iter())
            .map(|(&y_val, &fitted)| y_val - fitted)
            .collect();

        // Store matrices for bootstrap resampling
        let x_matrix = Mat::from_fn(x.nrows(), x.ncols(), |i, j| x[[i, j]]);
        let y_vector = y.to_vec();

        Ok(RegularizedFit {
            coefficients: result.params.to_vec(),
            fitted_values,
            residuals,
            n_obs: x.nrows(),
            x_matrix,
            y_vector,
            lambda,
            alpha: 1.0,
            iterations: result.iterations,
            converged: result.converged,
        })
    }
}

impl Ridge {
    /// Fit a Ridge regression model using coordinate descent
    ///
    /// This implementation uses coordinate descent optimization with L2 regularization
    /// to shrink coefficients toward zero without enforcing sparsity.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `lambda` - L2 regularization parameter (higher values = more regularization)
    /// * `config` - Optional coordinate descent configuration
    pub fn fit(
        x: ArrayView2<f64>,
        y: ArrayView1<f64>,
        lambda: f64,
        config: Option<CoordinateDescentConfig>,
    ) -> Result<RegularizedFit, ModelError> {
        let mut config = config.unwrap_or_default();
        config.lambda = lambda;
        config.alpha = 0.0; // Pure Ridge (L2 only)

        let result = coordinate_descent(x, y, Some(config))
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        let fitted_values: Vec<f64> = result.linear_predictor.to_vec();
        let residuals: Vec<f64> = y
            .iter()
            .zip(fitted_values.iter())
            .map(|(&y_val, &fitted)| y_val - fitted)
            .collect();

        // Store matrices for bootstrap resampling
        let x_matrix = Mat::from_fn(x.nrows(), x.ncols(), |i, j| x[[i, j]]);
        let y_vector = y.to_vec();

        Ok(RegularizedFit {
            coefficients: result.params.to_vec(),
            fitted_values,
            residuals,
            n_obs: x.nrows(),
            x_matrix,
            y_vector,
            lambda,
            alpha: 0.0,
            iterations: result.iterations,
            converged: result.converged,
        })
    }
}

impl Fit for LmFit {
    fn coefficients(&self) -> &[f64] {
        &self.coefficients
    }

    fn fitted(&self) -> &[f64] {
        &self.fitted_values
    }

    fn residuals(&self) -> &[f64] {
        &self.residuals
    }

    fn summary(&self) -> ModelSummary {
        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};

        // Calculate residual standard error: s² = RSS / (n - p)
        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
        let df_resid = self.df_resid() as f64;
        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
        let residual_std_error = mse.sqrt();

        // Calculate Total Sum of Squares (TSS) and R-squared
        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
            .sum::<f64>()
            / self.n_obs as f64;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
            .sum();

        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };

        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
        let n = self.n_obs as f64;
        let p = self.rank as f64;
        let adj_r_squared = if n > 1.0 && p > 0.0 {
            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
        } else {
            r_squared
        };

        // F-statistic for overall model significance
        // RSS for null model (intercept only) equals TSS
        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
        let f_statistic = if df_model > 0 {
            model_f_statistic(rss, tss, df_model, self.df_resid())
        } else {
            0.0
        };

        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
        } else {
            1.0
        };

        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
        // Compute X'X
        let xtx = self.x_matrix.transpose() * &self.x_matrix;

        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
        let qr = xtx.col_piv_qr();
        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
        let xtx_inv = qr.solve(&identity);

        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
        let std_errors: Vec<f64> = (0..self.coefficients.len())
            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
            .collect();

        let t_stats = t_statistics(&self.coefficients, &std_errors);
        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);

        let mut coefficient_rows = Vec::new();
        for (i, &coef) in self.coefficients.iter().enumerate() {
            let name = if i == 0 {
                "Intercept".to_string()
            } else {
                format!("X{}", i)
            };

            coefficient_rows.push(CoefficientRow {
                name,
                estimate: coef,
                std_error: std_errors[i],
                t_value: t_stats[i],
                p_value: p_values[i],
            });
        }

        ModelSummary {
            coefficients: coefficient_rows,
            r_squared,
            adj_r_squared,
            residual_std_error,
            f_statistic,
            f_p_value,
            df_model,
            df_residual: self.df_resid(),
        }
    }
}

impl Fit for GlmFit {
    fn coefficients(&self) -> &[f64] {
        &self.coefficients
    }

    fn fitted(&self) -> &[f64] {
        &self.fitted_values
    }

    fn residuals(&self) -> &[f64] {
        &self.residuals
    }

    fn summary(&self) -> ModelSummary {
        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};

        // For GLM, use deviance-based statistics
        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
        let n = self.n_obs as f64;
        let p = self.coefficients.len() as f64;
        let df_resid = (n - p).max(0.0);

        // Use deviance for dispersion estimation in GLM
        let dispersion = if df_resid > 0.0 {
            self.deviance / df_resid
        } else {
            1.0
        };
        let residual_std_error = dispersion.sqrt();

        // For GLM, R² is calculated differently (based on deviance)
        // Null deviance would be calculated with intercept-only model
        // For now, use a simplified version
        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid)
            .sum::<f64>()
            / n;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
            .sum();

        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
        let adj_r_squared = if n > 1.0 && p > 0.0 {
            1.0 - (rss / df_resid) / (tss / (n - 1.0))
        } else {
            r_squared
        };

        // F-statistic for overall model significance
        let df_model = if p > 1.0 { p as usize - 1 } else { 0 }; // exclude intercept
        let f_statistic = if df_model > 0 {
            model_f_statistic(rss, tss, df_model, df_resid as usize)
        } else {
            0.0
        };

        let f_p_value = if df_model > 0 && df_resid > 0.0 {
            f_test_p_value(f_statistic, df_model as i32, df_resid as i32)
        } else {
            1.0
        };

        // Calculate variance-covariance matrix using weights
        // For GLM: Var(β̂) = dispersion * (X'WX)^(-1)
        let n_vars = self.coefficients.len();
        let x_weighted = Mat::from_fn(self.n_obs, n_vars, |i, j| {
            self.weights[i].sqrt() * self.x_matrix[(i, j)]
        });

        let xtx = x_weighted.transpose() * &x_weighted;
        let qr = xtx.col_piv_qr();
        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
        let xtx_inv = qr.solve(&identity);

        // Standard errors for GLM
        let std_errors: Vec<f64> = (0..self.coefficients.len())
            .map(|i| (dispersion * xtx_inv[(i, i)]).sqrt())
            .collect();

        let t_stats = t_statistics(&self.coefficients, &std_errors);
        let p_values = t_test_p_values(&t_stats, df_resid as i32);

        let mut coefficient_rows = Vec::new();
        for (i, &coef) in self.coefficients.iter().enumerate() {
            let name = if i == 0 {
                "Intercept".to_string()
            } else {
                format!("X{}", i)
            };

            coefficient_rows.push(CoefficientRow {
                name,
                estimate: coef,
                std_error: std_errors[i],
                t_value: t_stats[i],
                p_value: p_values[i],
            });
        }

        ModelSummary {
            coefficients: coefficient_rows,
            r_squared,
            adj_r_squared,
            residual_std_error,
            f_statistic,
            f_p_value,
            df_model,
            df_residual: df_resid as usize,
        }
    }
}

impl Fit for RegularizedFit {
    fn coefficients(&self) -> &[f64] {
        &self.coefficients
    }

    fn fitted(&self) -> &[f64] {
        &self.fitted_values
    }

    fn residuals(&self) -> &[f64] {
        &self.residuals
    }

    fn summary(&self) -> ModelSummary {
        // For regularized models, traditional statistical inference is not applicable
        // since the coefficients are biased by design. We provide basic fit statistics.
        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
        let n = self.n_obs as f64;
        let p = self.coefficients.len() as f64;
        let df_resid = (n - p).max(0.0);

        let residual_std_error = if df_resid > 0.0 {
            (rss / df_resid).sqrt()
        } else {
            0.0
        };

        // Calculate R² for goodness of fit
        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid)
            .sum::<f64>()
            / n;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
            .sum();

        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
        let adj_r_squared = if n > 1.0 && p > 0.0 {
            1.0 - (rss / df_resid) / (tss / (n - 1.0))
        } else {
            r_squared
        };

        // For regularized models, we don't provide p-values as they're not meaningful
        let mut coefficient_rows = Vec::new();
        for (i, &coef) in self.coefficients.iter().enumerate() {
            let name = if i == 0 {
                "Intercept".to_string()
            } else {
                format!("X{}", i)
            };

            coefficient_rows.push(CoefficientRow {
                name,
                estimate: coef,
                std_error: f64::NAN, // Not meaningful for regularized models
                t_value: f64::NAN,   // Not meaningful for regularized models
                p_value: f64::NAN,   // Not meaningful for regularized models
            });
        }

        ModelSummary {
            coefficients: coefficient_rows,
            r_squared,
            adj_r_squared,
            residual_std_error,
            f_statistic: f64::NAN, // Not meaningful for regularized models
            f_p_value: f64::NAN,   // Not meaningful for regularized models
            df_model: 0,           // Not meaningful for regularized models
            df_residual: df_resid as usize,
        }
    }

    fn bootstrap(&self, n_samples: usize) -> Result<BootstrapResult, ModelError> {
        // Create bootstrap statistic that refits the regularized model
        let bootstrap_stat = RegularizedBootstrapStatistic {
            lambda: self.lambda,
            alpha: self.alpha,
        };

        let config = BootstrapConfig {
            n_samples,
            seed: Some(42), // For reproducible results
            parallel: true,
        };

        // Convert faer matrix to ndarray
        let mut x_data = Vec::with_capacity(self.n_obs * self.coefficients.len());
        for i in 0..self.n_obs {
            for j in 0..self.coefficients.len() {
                x_data.push(self.x_matrix[(i, j)]);
            }
        }
        let x_view =
            ndarray::ArrayView2::from_shape((self.n_obs, self.coefficients.len()), &x_data)
                .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        let y_view = ndarray::ArrayView1::from(&self.y_vector);

        bootstrap(x_view, y_view, bootstrap_stat, Some(config))
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))
    }
}

/// Bootstrap statistic for regularized models
struct RegularizedBootstrapStatistic {
    lambda: f64,
    alpha: f64,
}

impl BootstrapStatistic for RegularizedBootstrapStatistic {
    fn compute(&self, x: ArrayView2<f64>, y: ArrayView1<f64>) -> Array1<f64> {
        let config = CoordinateDescentConfig {
            lambda: self.lambda,
            alpha: self.alpha,
            ..Default::default()
        };

        match coordinate_descent(x, y, Some(config)) {
            Ok(result) => result.params,
            Err(_) => Array1::zeros(x.ncols()), // Return zeros on failure
        }
    }

    fn n_stats(&self) -> usize {
        // This will be determined dynamically based on the design matrix
        // For now, we'll use a reasonable default
        10
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_lm_fit_basic() {
        // Simple 2x2 identity matrix with response
        let x_data = vec![1.0, 0.0, 0.0, 1.0]; // 2x2 identity
        let y_data = vec![1.0, 2.0];

        let result = Lm::fit(&x_data, &y_data, 2, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();
        assert_eq!(fit.coefficients().len(), 2);
        assert_eq!(fit.fitted().len(), 2);
        assert_eq!(fit.residuals().len(), 2);
        assert_eq!(fit.n_obs, 2);
        assert_eq!(fit.rank, 2);
    }

    #[test]
    fn test_lm_simple_regression() {
        // Simple linear regression: y = 1 + 2*x + error
        // Design matrix with intercept column
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
        ];
        let y_data = vec![3.0, 5.0, 7.0]; // 1 + 2*x

        let result = Lm::fit(&x_data, &y_data, 3, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();

        // Check that we recovered the true coefficients (approximately)
        let coefs = fit.coefficients();
        assert!(
            (coefs[0] - 1.0).abs() < 1e-10,
            "Intercept should be ~1.0, got {}",
            coefs[0]
        );
        assert!(
            (coefs[1] - 2.0).abs() < 1e-10,
            "Slope should be ~2.0, got {}",
            coefs[1]
        );

        // Check dimensions
        assert_eq!(fit.n_obs, 3);
        assert_eq!(fit.rank, 2);
    }

    #[test]
    fn test_lm_rank_deficient() {
        // Rank deficient matrix: second column = 2 * first column
        let x_data = vec![
            1.0, 2.0, // [1, 2]
            2.0, 4.0, // [2, 4]
            3.0, 6.0, // [3, 6]
        ];
        let y_data = vec![1.0, 2.0, 3.0];

        let result = Lm::fit(&x_data, &y_data, 3, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();

        // Matrix rank should be correctly detected as 1 (second column = 2 * first column)
        assert_eq!(fit.n_obs(), 3);
        assert_eq!(fit.rank(), 1); // Correctly detected rank-deficient matrix
        assert_eq!(fit.df_resid(), 2); // 3 obs - 1 rank = 2 df

        // The key is that coefficients should still be computed without crashing
        assert_eq!(fit.coefficients().len(), 2);
    }

    #[test]
    fn test_lm_summary() {
        // Use a case with some residual variation for meaningful standard errors
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
            1.0, 4.0, // [1, x4]
        ];
        let y_data = vec![2.1, 4.0, 5.9, 8.1]; // approximately y = 2*x with some noise

        let fit = Lm::fit(&x_data, &y_data, 4, 2).unwrap();
        let summary = fit.summary();

        assert!(!summary.coefficients.is_empty());
        assert_eq!(summary.coefficients[0].name, "Intercept");
        assert_eq!(summary.coefficients.len(), 2);

        // Verify that standard errors are computed (not zero or placeholder)
        for coef_row in &summary.coefficients {
            assert!(
                coef_row.std_error > 0.0,
                "Standard error should be positive: {}",
                coef_row.std_error
            );
            assert!(
                coef_row.p_value >= 0.0 && coef_row.p_value <= 1.0,
                "P-value should be between 0 and 1"
            );
        }
    }

    #[test]
    fn test_statistical_inference_known_case() {
        // Simple case: y = 1 + 2*x (exact linear relationship)
        let x_data = vec![
            1.0, 1.0, // [1, x1] where x1 = 1
            1.0, 2.0, // [1, x2] where x2 = 2
            1.0, 3.0, // [1, x3] where x3 = 3
        ];
        let y_data = vec![3.0, 5.0, 7.0]; // y = 1 + 2*x

        let fit = Lm::fit(&x_data, &y_data, 3, 2).unwrap();
        let summary = fit.summary();

        // With perfect linear fit, residuals should be very small
        assert!(
            fit.residuals().iter().all(|&r| r.abs() < 1e-10),
            "Residuals should be near zero for perfect fit"
        );

        // Coefficients should be exactly recovered
        let coefs = fit.coefficients();
        assert!((coefs[0] - 1.0).abs() < 1e-10, "Intercept should be 1.0");
        assert!((coefs[1] - 2.0).abs() < 1e-10, "Slope should be 2.0");

        // For perfect fit with 1 degree of freedom, statistics should be extreme
        assert_eq!(summary.coefficients.len(), 2);
        println!("Summary: {:?}", summary);
    }

    #[test]
    fn test_enhanced_summary_statistics() {
        // Test with data that has some variation for meaningful R²
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
            1.0, 4.0, // [1, x4]
            1.0, 5.0, // [1, x5]
        ];
        let y_data = vec![2.1, 3.9, 6.1, 7.9, 10.1]; // approximately y = 2*x with noise

        let fit = Lm::fit(&x_data, &y_data, 5, 2).unwrap();
        let summary = fit.summary();

        // Verify enhanced summary includes all R-parity statistics
        assert!(
            summary.r_squared >= 0.0 && summary.r_squared <= 1.0,
            "R² should be between 0 and 1"
        );
        assert!(
            summary.adj_r_squared <= summary.r_squared,
            "Adjusted R² should be ≤ R²"
        );
        assert!(
            summary.residual_std_error > 0.0,
            "Residual standard error should be positive"
        );
        assert!(
            summary.f_statistic >= 0.0,
            "F-statistic should be non-negative"
        );
        assert!(
            summary.f_p_value >= 0.0 && summary.f_p_value <= 1.0,
            "F p-value should be between 0 and 1"
        );
        assert_eq!(
            summary.df_model, 1,
            "Model should have 1 degree of freedom (excluding intercept)"
        );
        assert_eq!(
            summary.df_residual, 3,
            "Should have 3 residual degrees of freedom (5 obs - 2 params)"
        );

        // With decent fit, R² should be reasonably high
        assert!(
            summary.r_squared > 0.8,
            "R² should be high for this near-linear relationship: {}",
            summary.r_squared
        );

        println!("Enhanced summary statistics:");
        println!("R² = {:.6}", summary.r_squared);
        println!("Adj R² = {:.6}", summary.adj_r_squared);
        println!("Residual SE = {:.6}", summary.residual_std_error);
        println!("F-statistic = {:.6}", summary.f_statistic);
        println!("F p-value = {:.6}", summary.f_p_value);
    }

    #[test]
    fn test_multicollinearity_debug() {
        // Test with non-collinear data to check if our fix works
        let n_obs = 8;
        let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
        let x2_values: Vec<f64> = (1..=n_obs)
            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
            .collect();
        let y_values: Vec<f64> = x1_values
            .iter()
            .zip(x2_values.iter())
            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
            .collect();

        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
        let mut x_data = Vec::with_capacity(n_obs * 3);
        for i in 0..n_obs {
            x_data.push(1.0); // intercept
            x_data.push(x1_values[i]); // x1
            x_data.push(x2_values[i]); // x2
        }

        println!("=== Multiple Regression Debug ===");
        println!("x1: {:?}", x1_values);
        println!("x2: {:?}", x2_values);
        println!("x2 is not perfectly correlated with x1");

        let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
        let _y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);

        println!("Design matrix X (first 3 rows):");
        for i in 0..3 {
            println!(
                "  [{}, {}, {}]",
                x_mat[(i, 0)],
                x_mat[(i, 1)],
                x_mat[(i, 2)]
            );
        }

        let qr = x_mat.col_piv_qr();
        let r_matrix = qr.R();

        println!("R matrix diagonal:");
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            println!("  R[{},{}] = {}", i, i, r_matrix[(i, i)]);
        }

        // Detect rank
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }
        println!("Detected rank: {} (should be 3 for full rank)", rank);

        let fit = Lm::fit(&x_data, &y_values, n_obs, 3).unwrap();
        println!("Our coefficients: {:?}", fit.coefficients());
        println!("Our rank: {}", fit.rank());

        // Check if coefficients are numerically stable
        for (i, &coef) in fit.coefficients().iter().enumerate() {
            if coef.abs() > 1e6 {
                println!(
                    "WARNING: Coefficient {} is numerically unstable: {}",
                    i, coef
                );
            }
        }
    }

    #[test]
    fn test_glm_gaussian_basic() {
        // Test GLM with Gaussian family (should match OLS)
        use family::Gaussian;
        use ndarray::Array2;

        let x_data = Array2::from_shape_vec(
            (3, 2),
            vec![
                1.0, 1.0, // [intercept, x1]
                1.0, 2.0, // [intercept, x2]
                1.0, 3.0, // [intercept, x3]
            ],
        )
        .unwrap();
        let y_data = ndarray::Array1::from(vec![3.0, 5.0, 7.0]); // 1 + 2*x

        let family = Gaussian;
        let result = Glm::fit_ndarray(x_data.view(), y_data.view(), family, None, None);
        assert!(result.is_ok(), "GLM fitting should succeed");

        let fit = result.unwrap();
        assert!(fit.converged(), "IRLS should converge for Gaussian GLM");

        // Should match OLS results for Gaussian family
        let coefs = fit.coefficients();
        assert!(
            (coefs[0] - 1.0).abs() < 1e-6,
            "Intercept should be ~1.0, got {}",
            coefs[0]
        );
        assert!(
            (coefs[1] - 2.0).abs() < 1e-6,
            "Slope should be ~2.0, got {}",
            coefs[1]
        );

        println!("GLM Gaussian test passed: coefficients = {:?}", coefs);
        println!(
            "Iterations: {}, Deviance: {:.6}",
            fit.iterations(),
            fit.deviance()
        );
    }

    #[test]
    fn test_glm_poisson_basic() {
        // Test GLM with Poisson family
        use family::Poisson;
        use ndarray::Array2;

        // Generate Poisson-like data: log(μ) = β₀ + β₁*x
        let x_data = Array2::from_shape_vec(
            (5, 2),
            vec![
                1.0, 0.0, // [intercept, x1]
                1.0, 1.0, // [intercept, x2]
                1.0, 2.0, // [intercept, x3]
                1.0, 3.0, // [intercept, x4]
                1.0, 4.0, // [intercept, x5]
            ],
        )
        .unwrap();

        // Poisson counts (approximately following log(μ) = 1 + 0.5*x)
        let y_data = ndarray::Array1::from(vec![3.0, 4.0, 6.0, 8.0, 12.0]); // ~ exp(1 + 0.5*x)

        let family = Poisson;
        let result = Glm::fit_ndarray(x_data.view(), y_data.view(), family, None, None);
        assert!(result.is_ok(), "Poisson GLM fitting should succeed");

        let fit = result.unwrap();
        assert!(fit.converged(), "IRLS should converge for Poisson GLM");

        let coefs = fit.coefficients();

        // Check that coefficients are reasonable (not exact due to IRLS)
        assert!(
            coefs[0] > 0.5 && coefs[0] < 1.5,
            "Intercept should be ~1.0, got {}",
            coefs[0]
        );
        assert!(
            coefs[1] > 0.2 && coefs[1] < 0.8,
            "Slope should be ~0.5, got {}",
            coefs[1]
        );

        println!("GLM Poisson test passed: coefficients = {:?}", coefs);
        println!(
            "Iterations: {}, Deviance: {:.6}",
            fit.iterations(),
            fit.deviance()
        );
    }

    #[test]
    fn test_lm_fit_ndarray_api() {
        // Test the modern ndarray API
        // Simple linear regression: y = 1 + 2*x
        let x_data = ndarray::Array2::from_shape_vec(
            (3, 2),
            vec![
                1.0, 1.0, // [intercept, x1]
                1.0, 2.0, // [intercept, x2]
                1.0, 3.0, // [intercept, x3]
            ],
        )
        .unwrap();
        let y_data = ndarray::Array1::from(vec![3.0, 5.0, 7.0]); // 1 + 2*x

        let fit = Lm::fit_ndarray(x_data.view(), y_data.view()).unwrap();

        // Check that we recovered the true coefficients (approximately)
        let coefs = fit.coefficients();
        assert!(
            (coefs[0] - 1.0).abs() < 1e-10,
            "Intercept should be ~1.0, got {}",
            coefs[0]
        );
        assert!(
            (coefs[1] - 2.0).abs() < 1e-10,
            "Slope should be ~2.0, got {}",
            coefs[1]
        );

        // Check dimensions
        assert_eq!(fit.n_obs(), 3);
        assert_eq!(fit.rank(), 2);

        // Should match legacy API
        let x_flat = vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0];
        let y_flat = vec![3.0, 5.0, 7.0];
        let legacy_fit = Lm::fit(&x_flat, &y_flat, 3, 2).unwrap();

        // Results should be identical
        for (new_coef, legacy_coef) in coefs.iter().zip(legacy_fit.coefficients().iter()) {
            assert!(
                (new_coef - legacy_coef).abs() < 1e-12,
                "Modern and legacy APIs should produce identical results"
            );
        }
    }
}

